export const CACHE_KEYS = {
  MENU: 'app_cache_menu',
  USER_FAVORITES: 'app_cache_favorites',
};

const DEFAULT_TTL = 1000 * 60 * 60; // 1 hour

interface CacheItem<T> {
  data: T;
  expiry: number;
}

export const cacheService = {
  set: <T>(key: string, data: T, ttl: number = DEFAULT_TTL): void => {
    try {
      const item: CacheItem<T> = {
        data,
        expiry: Date.now() + ttl,
      };
      localStorage.setItem(key, JSON.stringify(item));
    } catch (e) {
      // Check for quota exceeded error
      if (e instanceof DOMException && 
          (e.name === 'QuotaExceededError' || 
           e.name === 'NS_ERROR_DOM_QUOTA_REACHED' || 
           e.code === 22)) {

        console.warn('LocalStorage quota exceeded. Purging all app caches and retrying...');

        // Attempt a more aggressive cleanup: Clear ALL localStorage to ensure max possible space
        try {
          // We only clear our own keys to be responsible, but if that's not enough, 
          // a cache is disposable by definition.
          Object.values(CACHE_KEYS).forEach(k => localStorage.removeItem(k));

          const item: CacheItem<T> = {
            data,
            expiry: Date.now() + ttl,
          };
          localStorage.setItem(key, JSON.stringify(item));
        } catch (retryError) {
          // If it still fails, the data is simply too large for LocalStorage (likely > 5MB)
          // We fail silently here because caching is an optimization, not a requirement.
          console.error('Data too large for LocalStorage even after clearing space. Cache skipped.', retryError);
        }
      } else {
        console.warn('Failed to save to cache', e);
      }
    }
  },

  get: <T>(key: string): T | null => {
    try {
      const itemStr = localStorage.getItem(key);
      if (!itemStr) return null;

      const item: CacheItem<T> = JSON.parse(itemStr);
      if (Date.now() > item.expiry) {
        localStorage.removeItem(key);
        return null;
      }
      return item.data;
    } catch (e) {
      return null;
    }
  },

  remove: (key: string): void => {
    localStorage.removeItem(key);
  },

  clearAll: (): void => {
      Object.values(CACHE_KEYS).forEach(key => localStorage.removeItem(key));
  }
};

