export const CACHE_KEYS = {
  MENU: 'app_cache_menu',
  USER_FAVORITES: 'app_cache_favorites',
};

const DEFAULT_TTL = 1000 * 60 * 60; // 1 hour

interface CacheItem<T> {
  data: T;
  expiry: number;
}

export const cacheService = {
  set: <T>(key: string, data: T, ttl: number = DEFAULT_TTL): void => {
    try {
      const item: CacheItem<T> = {
        data,
        expiry: Date.now() + ttl,
      };
      localStorage.setItem(key, JSON.stringify(item));
    } catch (e) {
      // Check for quota exceeded error
      if (e instanceof DOMException && 
          (e.name === 'QuotaExceededError' || 
           e.name === 'NS_ERROR_DOM_QUOTA_REACHED' || 
           e.code === 22)) {

        console.warn(`LocalStorage quota exceeded for key: ${key}. Attempting recovery...`);

        // Strategy 1: Clear other app caches
        Object.values(CACHE_KEYS).forEach(k => {
          if (k !== key) localStorage.removeItem(k);
        });

        try {
          const item: CacheItem<T> = { data, expiry: Date.now() + ttl };
          localStorage.setItem(key, JSON.stringify(item));
          return;
        } catch (retryError) {
          // Strategy 2: If it's the menu, try saving a "lite" version without images
          if (key === CACHE_KEYS.MENU && Array.isArray(data)) {
            console.warn('Payload still too large. Saving lite version (no images) to cache.');
            const liteData = data.map((item: any) => ({
              ...item,
              imageUrl: '' // Strip large base64/image data for cache
            }));

            try {
              const liteItem: CacheItem<any> = { data: liteData, expiry: Date.now() + ttl };
              localStorage.setItem(key, JSON.stringify(liteItem));
              return;
            } catch (liteError) {
              console.error('Even lite version failed to cache.', liteError);
            }
          }

          // Strategy 3: Just give up on caching this item. Don't crash the app.
          console.error('Data too large for LocalStorage. Cache skipped.', retryError);
        }
      } else {
        console.warn('Failed to save to cache', e);
      }
    }
  },

  get: <T>(key: string): T | null => {
    try {
      const itemStr = localStorage.getItem(key);
      if (!itemStr) return null;

      const item: CacheItem<T> = JSON.parse(itemStr);
      if (Date.now() > item.expiry) {
        localStorage.removeItem(key);
        return null;
      }
      return item.data;
    } catch (e) {
      return null;
    }
  },

  remove: (key: string): void => {
    localStorage.removeItem(key);
  },

  clearAll: (): void => {
      Object.values(CACHE_KEYS).forEach(key => localStorage.removeItem(key));
  }
};

